# Verify against JSON
import pathlib
root = pathlib.Path(__file__).resolve().parents[1]
lib = json.loads((root / "data" / "prompt_deep_causes.json").read_text(encoding="utf-8"))
need = set()
for v in lib.values():
    for x in v.get("influences", []):
        need.add(x)
missing = need - set(M.keys())
extra = set(M.keys()) - need
if missing:
    raise SystemExit("Missing keys:\n" + "\n".join(sorted(missing)))
if extra:
    raise SystemExit("Extra keys:\n" + "\n".join(sorted(extra)))

def js_escape(s: str) -> str:
    return json.dumps(s, ensure_ascii=False)[1:-1]

lines = ["  const HYPOTHESIS_EXACT_PHRASE = {"]
for k in sorted(M.keys()):
    lines.append(f'    "{js_escape(k)}":')
    lines.append(f'      "{js_escape(M[k])}",')
lines.append("  };")
out = root / "hypothesis_block.txt"
out.write_text("\n".join(lines) + f"\n// {len(M)} entries OK\n", encoding="utf-8")
print("Wrote", out)
